	// flags: -tun -uapi -secs -role  (all key=value after 'run')
	args := map[string]string{}
	for _, a := range os.Args[2:] {
		p := strings.SplitN(a, "=", 2)
		if len(p) == 2 {
			args[p[0]] = p[1]
		}
	}
	tunName := mustArg(args, "tun")
	uapiFile := mustArg(args, "uapi")
	role := mustArg(args, "role")
	secs, _ := strconv.Atoi(mustArg(args, "secs"))

	uapiBytes, err := os.ReadFile(uapiFile)
	if err != nil {
		panic(err)
	}

	tdev, err := tun.CreateTUN(tunName, 1420)
	if err != nil {
		panic(fmt.Sprintf("CreateTUN: %v", err))
	}
	logger := device.NewLogger(device.LogLevelVerbose, "["+role+"] ")
	dev := device.NewDevice(tdev, conn.NewDefaultBind(), logger)

	if err := dev.IpcSet(string(uapiBytes)); err != nil {
		panic(fmt.Sprintf("IpcSet: %v", err))
	}
	if err := dev.Up(); err != nil {
		panic(fmt.Sprintf("Up: %v", err))
	}
	logger.Verbosef("=== device up, role=%s tun=%s ===", role, tunName)

	// poll IpcGet for handshake + byte counters each second
	establishedAt := -1
	for i := 0; i < secs; i++ {
		time.Sleep(1 * time.Second)
		get, err := dev.IpcGet()
		if err != nil {
			logger.Errorf("IpcGet: %v", err)
			continue
		}
		var hs, rx, tx string
		for _, line := range strings.Split(get, "\n") {
			if strings.HasPrefix(line, "last_handshake_time_sec=") {
				hs = strings.TrimPrefix(line, "last_handshake_time_sec=")
			}
			if strings.HasPrefix(line, "rx_bytes=") {
				rx = strings.TrimPrefix(line, "rx_bytes=")
			}
			if strings.HasPrefix(line, "tx_bytes=") {
				tx = strings.TrimPrefix(line, "tx_bytes=")
			}
		}
		hsNonZero := hs != "" && hs != "0"
		if hsNonZero && establishedAt < 0 {
			establishedAt = i + 1
		}
		fmt.Printf("STAT role=%s t=%ds last_handshake_sec=%s rx_bytes=%s tx_bytes=%s established=%v\n",
			role, i+1, hs, rx, tx, hsNonZero)
	}
	if establishedAt >= 0 {
		fmt.Printf("RESULT role=%s ESTABLISHED_AT=%ds\n", role, establishedAt)
	} else {
		fmt.Printf("RESULT role=%s NEVER_ESTABLISHED\n", role)
	}
	dev.Close()
}

